const ST_COLORS   = { available:"#10b981", out:"#ff8c00", maintenance:"#6b7280", booked:"#3b82f6", returned:"#10b981", partially_returned:"#ff8c00", active:"#ff8c00", upcoming:"#8b5cf6", completed:"#6b7280" };
const AV_COLORS   = ["#ff8c00","#8b5cf6","#10b981","#3b82f6","#ef4444","#06b6d4"];
const ROLE_LABELS = { admin:"Manager", warehouse:"Warehouse", hod_audio:"Audio HOD", hod_lighting:"Lighting HOD", hod_rigging:"Structures HOD", hod_power:"Power HOD", hod_av:"AV/LED HOD", crew:"Crew", freelancer:"Freelancer" };
const HOD_ROLES = ["hod_audio","hod_lighting","hod_rigging","hod_power","hod_av"];
const canReportFault = (role) => HOD_ROLES.includes(role) || role==="admin" || role==="warehouse";
const isManager = (role) => role==="admin";
const canScanOut = (role) => role==="admin" || role==="warehouse" || role==="crew" || HOD_ROLES.includes(role);
const isFreelancer = (role) => role==="freelancer";

function quoteStatus(q){
  if(!q.checkedOutAt) return "booked";
  const total=q.lines.length, ret=q.lines.filter(l=>l.status==="returned").length;
  if(ret===0) return "out";
  if(ret<total) return "partially_returned";
  return "returned";
}
function unitIsOut(unitId,quotes,excludeId=null){
  return quotes.some(q=>q.id!==excludeId&&q.lines.some(l=>l.unitId===unitId&&l.status==="out"));
}
function fmt(dt){ if(!dt) return "—"; return new Date(dt).toLocaleString("en-GB",{day:"2-digit",month:"short",hour:"2-digit",minute:"2-digit"}); }
function genBarcode(units){ const nums=units.map(u=>+u.id.replace("U","")).filter(Boolean); const next=nums.length?Math.max(...nums)+1:1; return { id:`U${String(next).padStart(3,"0")}`, barcode:`BC-U${String(next).padStart(3,"0")}` }; }

function Badge({label,color}){ const txt=label==="partially_returned"?"part. returned":label; return <span style={{background:color+"22",color,border:`1px solid ${color}44`,borderRadius:6,padding:"2px 10px",fontSize:11,fontWeight:700,textTransform:"uppercase",whiteSpace:"nowrap"}}>{txt}</span>; }
function Av({initials,color="#ff8c00",size=36}){ return <div style={{width:size,height:size,borderRadius:"50%",background:color,color:"#fff",display:"flex",alignItems:"center",justifyContent:"center",fontWeight:800,fontSize:size*0.35,flexShrink:0}}>{initials}</div>; }
function Card({children,style={}}){ return <div style={{background:"#161b27",border:"1px solid #2a2a3a",borderRadius:14,padding:20,...style}}>{children}</div>; }
function Lbl({children}){ return <label style={{color:"#9ca3af",fontSize:12,fontWeight:600,textTransform:"uppercase",letterSpacing:".05em",display:"block",marginBottom:5}}>{children}</label>; }
function TI({label,value,onChange,type="text",placeholder="",mono=false,error=""}){
  return(<div>{label&&<Lbl>{label}</Lbl>}<input value={value} onChange={e=>onChange(e.target.value)} type={type} placeholder={placeholder} style={{width:"100%",padding:"9px 12px",background:"#0d1117",border:`1px solid ${error?"#ef4444":"#2a2a3a"}`,borderRadius:8,color:"#fff",fontSize:13,outline:"none",boxSizing:"border-box",fontFamily:mono?"monospace":"inherit"}}/>{error&&<div style={{color:"#ef4444",fontSize:11,marginTop:3}}>{error}</div>}</div>);
}
function Btn({children,onClick,color="#ff8c00",outline=false,small=false,disabled=false,full=false}){
  return <button onClick={onClick} disabled={disabled} style={{padding:small?"5px 12px":"9px 18px",width:full?"100%":"auto",borderRadius:8,border:outline?`1px solid ${color}`:"none",background:outline?"transparent":disabled?"#1f2937":color,color:outline?color:"#fff",fontWeight:700,fontSize:small?12:14,cursor:disabled?"not-allowed":"pointer",opacity:disabled?.5:1,whiteSpace:"nowrap",boxSizing:"border-box"}}>{children}</button>;
}
function Sel({label,value,onChange,children,style={}}){
  return(<div style={style}>{label&&<Lbl>{label}</Lbl>}<select value={value} onChange={e=>onChange(e.target.value)} style={{width:"100%",padding:"9px 12px",background:"#0d1117",border:"1px solid #2a2a3a",borderRadius:8,color:"#fff",fontSize:13,outline:"none"}}>{children}</select></div>);
}
function Modal({title,children,onClose,width=540}){
  return(
    <div style={{position:"fixed",inset:0,background:"#000000cc",display:"flex",alignItems:"center",justifyContent:"center",zIndex:1000,padding:20}}>
      <div style={{background:"#161b27",border:"1px solid #2a2a3a",borderRadius:18,padding:28,width:"100%",maxWidth:width,boxShadow:"0 40px 80px #00000099",maxHeight:"92vh",overflowY:"auto"}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:22}}>
          <div style={{color:"#fff",fontWeight:800,fontSize:18}}>{title}</div>
          <button onClick={onClose} style={{background:"none",border:"none",color:"#6b7280",fontSize:22,cursor:"pointer"}}>✕</button>
        </div>
        {children}
      </div>
    </div>
  );
}

function QRSvg({code,size=70}){
  let hash=0; for(let i=0;i<code.length;i++) hash=(hash*31+code.charCodeAt(i))>>>0;
  const n=10; const cells=Array.from({length:n*n},(_,i)=>{ const r=Math.floor(i/n),c=i%n; return((hash^(r*97+c*31)^(r<<4)^(c<<2))%7)<3; });
  [0,1,2,3,10,11,12,13,20,21,22,23,30,31,32,33,6,7,16,17,26,27,36,37,66,67,76,77,86,87,96,97,60,61,70,71,80,81,90,91].forEach(i=>{if(i<cells.length)cells[i]=true;});
  const cell=size/n;
  return(<div style={{display:"inline-block",background:"#fff",padding:6,borderRadius:8}}><svg width={size} height={size}>{cells.map((on,i)=>on&&<rect key={i} x={(i%n)*cell} y={Math.floor(i/n)*cell} width={cell-1} height={cell-1} fill="#111"/>)}</svg><div style={{textAlign:"center",fontSize:9,fontFamily:"monospace",color:"#333",marginTop:2}}>{code}</div></div>);
}

// LOGIN
function Login({onLogin}){
  const [email,setEmail]=useState(""); const [pw,setPw]=useState(""); const [err,setErr]=useState(""); const [busy,setBusy]=useState(false);
  const go=()=>{ setErr(""); setBusy(true); setTimeout(()=>{ const u=USERS.find(u=>u.email===email&&u.password===pw); if(u)onLogin(u); else{setErr("Invalid credentials.");setBusy(false);} },500); };
  return(
    <div style={{minHeight:"100vh",background:"#0d1117",display:"flex",alignItems:"center",justifyContent:"center",fontFamily:"'DM Sans',sans-serif"}}>
      <div style={{width:400,padding:40,background:"#161b27",borderRadius:20,border:"1px solid #2a2a3a",boxShadow:"0 40px 80px #00000088"}}>
        <div style={{marginBottom:28,textAlign:"center"}}>
          <img src={LOGO_B64} alt="Eventech" style={{width:200,marginBottom:12,borderRadius:8}}/>
          <div style={{color:"#9ca3af",fontSize:13}}>Warehouse Management System</div>
        </div>
        <div style={{display:"flex",flexDirection:"column",gap:12}}>
          <TI label="Email" value={email} onChange={setEmail} placeholder="you@eventech.co.za"/>
          <div><Lbl>Password</Lbl>
            <input value={pw} onChange={e=>setPw(e.target.value)} type="password" placeholder="••••••••" onKeyDown={e=>e.key==="Enter"&&go()}
              style={{width:"100%",padding:"9px 12px",background:"#0d1117",border:"1px solid #2a2a3a",borderRadius:8,color:"#fff",fontSize:13,outline:"none",boxSizing:"border-box"}}/>
          </div>
        </div>
        {err&&<div style={{color:"#ef4444",fontSize:13,marginTop:10}}>{err}</div>}
        <button onClick={go} disabled={busy} style={{width:"100%",marginTop:18,padding:12,background:"#ff8c00",border:"none",borderRadius:10,color:"#fff",fontWeight:700,fontSize:15,cursor:"pointer",opacity:busy?.7:1}}>{busy?"Signing in…":"Sign In"}</button>
        <div style={{marginTop:16,textAlign:"center"}}>
          <div style={{color:"#4b5563",fontSize:12}}>Contact your manager if you have trouble logging in.</div>
        </div>
      </div>
    </div>
  );
}

