function usePersisted(key, fallback){
  const [val,setVal]=useState(()=>{
    try{
      const stored=localStorage.getItem("et_"+key);
      return stored?JSON.parse(stored):fallback;
    }catch{ return fallback; }
  });
  const setPersisted=(next)=>{
    const resolved=typeof next==="function"?next(val):next;
    setVal(resolved);
    try{ localStorage.setItem("et_"+key,JSON.stringify(resolved)); }catch{}
  };
  return [val,setPersisted];
}

export default function App(){
  const [user,setUser]=useState(()=>{
    try{ const s=localStorage.getItem("et_session"); return s?JSON.parse(s):null; }catch{ return null; }
  });
  const [tab,setTab]=useState("dashboard");

  const [equipTypes,setEquipTypes]   = usePersisted("equipTypes",   INIT_EQUIPMENT_TYPES);
  const [units,setUnits]             = usePersisted("units",         INIT_UNITS);
  const [projects,setProjects]       = usePersisted("projects",      INIT_PROJECTS);
  const [crew,setCrew]               = usePersisted("crew",          INIT_CREW_DATA);
  const [faultReports,setFaultReports]=usePersisted("faultReports",  []);
  const [vehicles,setVehicles]       = usePersisted("vehicles",      INIT_VEHICLES);
  const [freelancers,setFreelancers] = usePersisted("freelancers",   []);
  const [cableStock,setCableStock]   = usePersisted("cableStock",    INIT_CABLE_STOCK);
  const [dryHireItems,setDryHireItems]=usePersisted("dryHireItems",  []);
  const [stockTakes,setStockTakes]   = usePersisted("stockTakes",    []);
  const [quotes,setQuotes]           = usePersisted("quotes",        INIT_QUOTES);
  const [prepSheets,setPrepSheets]  = usePersisted("prepSheets",    []);

  const login=(u)=>{ setUser(u); try{localStorage.setItem("et_session",JSON.stringify(u));}catch{} };
  const logout=()=>{ setUser(null); setTab("dashboard"); try{localStorage.removeItem("et_session");}catch{} };

  const [showSettings,setShowSettings]=useState(false);

  if(!user) return <Login onLogin={login}/>;

  return(
    <div style={{display:"flex",height:"100vh",background:"#0d1117",overflow:"hidden"}}>
      <Sidebar tab={tab} setTab={setTab} user={user} onLogout={logout} onOpenSettings={()=>setShowSettings(true)}/>
      <div style={{flex:1,overflowY:"auto"}}>
        {tab==="dashboard" &&<Dashboard units={units} equipTypes={equipTypes} projects={projects} quotes={quotes} faultReports={faultReports} prepSheets={prepSheets} setTab={setTab} user={user}/>}
        {tab==="calendar"  &&<CalendarPage projects={projects} quotes={quotes} units={units} crew={crew} user={user}/>}
        {tab==="scanout"  &&<ScanPage  quotes={quotes} setQuotes={setQuotes} units={units} setUnits={setUnits} equipTypes={equipTypes} vehicles={vehicles} setVehicles={setVehicles} crew={crew} user={user}/>}
        {tab==="quotes"   &&<QuotesPage quotes={quotes} units={units} equipTypes={equipTypes} projects={projects} user={user}/>}
        {tab==="assets"   &&<Assets equipTypes={equipTypes} setEquipTypes={setEquipTypes} units={units} setUnits={setUnits} cableStock={cableStock} setCableStock={setCableStock} quotes={quotes} user={user}/>}
        {tab==="faults"   &&<FaultReports faultReports={faultReports} setFaultReports={setFaultReports} units={units} equipTypes={equipTypes} user={user}/>}
        {tab==="stocktake" &&<StockTakePage stockTakes={stockTakes} setStockTakes={setStockTakes} units={units} equipTypes={equipTypes} quotes={quotes} user={user}/>}
        {tab==="projects" &&<Projects projects={projects} setProjects={setProjects} user={user}/>}
        {tab==="vehicles"   &&<VehiclesPage vehicles={vehicles} setVehicles={setVehicles} quotes={quotes} crew={crew} user={user}/>}
        {tab==="dryhire"    &&<DryHirePage dryHireItems={dryHireItems} setDryHireItems={setDryHireItems} quotes={quotes} user={user}/>}
        {tab==="freelancers"&&<FreelancersPage freelancers={freelancers} setFreelancers={setFreelancers} projects={projects} quotes={quotes} user={user}/>}
        {tab==="crew"       &&<Crew crew={crew} setCrew={setCrew} projects={projects} user={user}/>}
        {tab==="prepsheets" &&<PrepSheetsPage prepSheets={prepSheets} setPrepSheets={setPrepSheets} user={user}/>}
      </div>
      {showSettings&&(
        <UserSettingsModal
          user={user}
          onClose={()=>setShowSettings(false)}
          onSave={(updated)=>{
            // Update user in USERS array in memory and session
            const idx=USERS.findIndex(u=>u.id===user.id);
            if(idx!==-1){ USERS[idx]={...USERS[idx],...updated}; }
            const newUser={...user,...updated};
            setUser(newUser);
            try{localStorage.setItem("et_session",JSON.stringify(newUser));}catch{}
            setShowSettings(false);
          }}
        />
      )}
    </div>
  );
}
